import React, { useState, useEffect, useRef } from 'react';
import '../Styling/ReadingControls.css';

const STORAGE_KEY = 'ujlp_reading_prefs';

const defaultPrefs = {
  fontSize: 18,
  lineHeight: 1.6,
  fontFamily: 'serif'
};

function ReadingControls({ targetId = 'article-content' }) {
  const [prefs, setPrefs] = useState(defaultPrefs);
  const [open, setOpen] = useState(false);
  const panelRef = useRef(null);

  useEffect(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) setPrefs(JSON.parse(raw));
    } catch (e) {
      // ignore
    }
  }, []);

  useEffect(() => {
    const el = document.getElementById(targetId);
    if (!el) return;
    el.style.fontSize = `${prefs.fontSize}px`;
    el.style.lineHeight = prefs.lineHeight;
    el.style.fontFamily = prefs.fontFamily === 'serif' ? 'Georgia, "Times New Roman", Times, serif' : 'Inter, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial';

    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(prefs));
    } catch (e) { }
  }, [prefs, targetId]);

  useEffect(() => {
    const handler = (e) => {
      if (open && panelRef.current && !panelRef.current.contains(e.target)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  const change = (k, v) => setPrefs(p => ({ ...p, [k]: v }));

  return (
    <div className="reading-controls-compact" ref={panelRef}>
      <button
        className="reading-compact-button"
        aria-expanded={open}
        aria-controls="reading-panel"
        onClick={() => setOpen(o => !o)}
        title="Reading options"
      >
        🛈
      </button>

      {open && (
        <div className="reading-panel" id="reading-panel" role="dialog" aria-label="Reading options">
          <div className="panel-row">
            <label>
              <div className="panel-label">Font</div>
              <select value={prefs.fontFamily} onChange={(e) => change('fontFamily', e.target.value)}>
                <option value="serif">Serif</option>
                <option value="sans">Sans</option>
              </select>
            </label>

            <label>
              <div className="panel-label">Size</div>
              <div className="size-controls">
                <button onClick={() => change('fontSize', Math.max(14, prefs.fontSize - 1))} aria-label="Decrease font size">A-</button>
                <div className="size-value">{prefs.fontSize}px</div>
                <button onClick={() => change('fontSize', Math.min(28, prefs.fontSize + 1))} aria-label="Increase font size">A+</button>
              </div>
            </label>

            <label>
              <div className="panel-label">Spacing</div>
              <input
                type="range"
                min="1.2"
                max="2"
                step="0.05"
                value={prefs.lineHeight}
                onChange={(e) => change('lineHeight', parseFloat(e.target.value))}
              />
            </label>
          </div>

          <div className="panel-actions">
            <button className="reading-toggle" onClick={() => {
              const body = document.documentElement;
              const current = body.getAttribute('data-reading-mode');
              if (current === 'true') body.removeAttribute('data-reading-mode');
              else body.setAttribute('data-reading-mode', 'true');
            }} aria-pressed={document.documentElement.getAttribute('data-reading-mode') === 'true'}>
              Toggle Reading Mode
            </button>

            <button className="reading-close" onClick={() => setOpen(false)}>Close</button>
          </div>
        </div>
      )}
    </div>
  );
}

export default ReadingControls;
